 $yc = $y+$r;                $this->_out(sprintf('%.2F %.2F l', $xc*$k,($hp-$y)*$k ));                if (strpos($corners, '2')===false)                    $this->_out(sprintf('%.2F %.2F l', ($x+$w)*$k,($hp-$y)*$k ));                else                    $this->_Arc($xc + $r*$MyArc, $yc - $r, $xc + $r, $yc - $r*$MyArc, $xc + $r, $yc);                $xc = $x+$w-$r;                $yc = $y+$h-$r;                $this->_out(sprintf('%.2F %.2F l',($x+$w)*$k,($hp-$yc)*$k));                if (strpos($corners, '3')===false)                    $this->_out(sprintf('%.2F %.2F l',($x+$w)*$k,($hp-($y+$h))*$k));                else                    $this->_Arc($xc + $r, $yc + $r*$MyArc, $xc + $r*$MyArc, $yc + $r, $xc, $yc + $r);                $xc = $x+$r;                $yc = $y+$h-$r;                $this->_out(sprintf('%.2F %.2F l',$xc*$k,($hp-($y+$h))*$k));                if (strpos($corners, '4')===false)                    $this->_out(sprintf('%.2F %.2F l',($x)*$k,($hp-($y+$h))*$k));                else                    $this->_Arc($xc - $r*$MyArc, $yc + $r, $xc - $r, $yc + $r*$MyArc, $xc - $r, $yc);                $xc = $x+$r ;                $yc = $y+$r;                $this->_out(sprintf('%.2F %.2F l',($x)*$k,($hp-$yc)*$k ));                if (strpos($corners, '1')===false)                {                    $this->_out(sprintf('%.2F %.2F l',($x)*$k,($hp-$y)*$k ));                    $this->_out(sprintf('%.2F %.2F l',($x+$r)*$k,($hp-$y)*$k ));                }                else                    $this->_Arc($xc - $r, $yc - $r*$MyArc, $xc - $r*$MyArc, $yc - $r, $xc, $yc - $r);                $this->_out($op);            }            function _Arc($x1, $y1, $x2, $y2, $x3, $y3)            {                $h = $this->h;                $this->_out(sprintf('%.2F %.2F %.2F %.2F %.2F %.2F c ', $x1*$this->k, ($h-$y1)*$this->k,                    $x2*$this->k, ($h-$y2)*$this->k, $x3*$this->k, ($h-$y3)*$this->k));            }        }        $pdf = new PDF();foreach($tab_bls AS $id_bl) {    $pdf->SetAutoPageBreak(TRUE, '30');    $pdf->AliasNbPages();    $pdf->AddPage();    $pdf->SetFillColor(214, 214, 214);    $pdf->RoundedRect(105, 45, 95, 8, 3, '12', 'DF');    $pdf->RoundedRect(105, 53, 95, 25, 3, '34', 'D');//Adresse de factutation    $db->Query('SELECT bls.descriptif, clients.titre, clients.nom, clients.prenom, clients.adresse, clients.adresse_suite, clients.cp, clients.ville            FROM bls            INNER JOIN clients            ON (bls.id_client = clients.id)            AND (clients.compte_principal = "' . $_SESSION['compte_principal'] . '")            WHERE bls.compte_principal = "' . $_SESSION['compte_principal'] . '"            AND id_bl="' . $id_bl . '"            ');    $row = $db->Row();    $pdf->SetFont('Arial', 'BI', 12);    $pdf->Cell(95, 8, '', 0, 0, 'L', 0);    $pdf->Cell(95, 8, 'Adresse de facturation', 0, 0, 'L', 0);    $pdf->Ln();    $pdf->SetFont('Arial', '', 12);    $pdf->Cell(95, 6, '', 0, 0, 'L', 0);    $pdf->Cell(95, 6, utf8_decode($row->titre . ' ' . $row->nom . ' ' . $row->prenom), 0, 0, 'L', 0);    $pdf->Ln();    $pdf->Cell(95, 5, '', 0, 0, 'L', 0);    $pdf->Cell(95, 5, utf8_decode($row->adresse), 0, 0, 'L', 0);    $pdf->Ln();    $pdf->Cell(95, 5, '', 0, 0, 'L', 0);    $pdf->Cell(95, 5, utf8_decode($row->adresse_suite), 0, 0, 'L', 0);    $pdf->Ln();    $pdf->Cell(95, 5, '', 0, 0, 'L', 0);    $pdf->Cell(95, 5, utf8_decode($row->cp . ' ' . $row->ville), 0, 0, 'L', 0);    $pdf->Ln();    $pdf->Cell(95, 4, '', 0, 0, 'L', 0);    $pdf->Cell(95, 4, '', 0, 0, 'L', 0);//Descriptif des travaux    $pdf->Ln(6);    $pdf->RoundedRect(10, 80, 190, 8, 3, '12', 'DF');    $pdf->SetFillColor(214, 214, 214);    $pdf->SetFont('Arial', 'BI', 12);    $pdf->Cell(0, 8, 'Descriptif des travaux', 0, 0, 'L', 0);    $pdf->Ln();    $pdf->S